// Outbound: our packed ADV must round-trip through upstream's
// unpacker. Check by re-parsing it ourselves (good for regression),
// and by ensuring it's at least the same byte count as the upstream
// fixture for an equivalent ADV (catches gross msgpack mistypings).
func TestInteropOurADVMatchesUpstreamShape(t *testing.T) {
	upstreamBytes := loadFixture(t, "adv_minimal.bin")

	h := bytes.Repeat([]byte{0x11}, 32)
	r := []byte{0xAA, 0xBB, 0xCC, 0xDD}
	adv := &ResourceAdvertisement{
		TransferSize:  544,
		DataSize:      484,
		NumParts:      3,
		Hash:          h,
		RandomHash:    r,
		OriginalHash:  h,
		SegmentIndex:  1,
		TotalSegments: 1,
		Flags:         int(ResourceFlagEncrypted),
		Hashmap:       []byte{0xCA, 0xFE, 0x00, 0x01, 0xCA, 0xFE, 0x00, 0x02, 0xCA, 0xFE, 0x00, 0x03},
	}
	ours, err := PackResourceAdv(adv)
	if err != nil {
		t.Fatalf("PackResourceAdv: %v", err)
	}
	// Sanity: byte count within ±2 of upstream — different msgpack
	// libraries may pick slightly different int widths or map
	// orderings, but the gross size should match. A 10x difference
	// would indicate a structural mistake.
	if abs(len(ours)-len(upstreamBytes)) > 8 {
		t.Errorf("packed ADV size %d, upstream %d (delta > 8 bytes — investigate msgpack typing)", len(ours), len(upstreamBytes))
	}
	// Critical: upstream MUST be able to parse our bytes (we test
	// the inverse via fixtures above; this side closes the loop).
	parsed, err := ParseResourceAdv(ours)
	if err != nil {
		t.Fatalf("our ADV fails self-parse (definitely won't interop): %v", err)
	}
	if parsed.TransferSize != adv.TransferSize {
		t.Errorf("self-parse t=%d, want %d", parsed.TransferSize, adv.TransferSize)
	}
}

func abs(x int) int {
	if x < 0 {
		return -x
	}
	return x
}

// Defensive: a malformed-msgpack ADV body must surface as
// ErrResourceADVMalformed, not panic.
func TestInteropMalformedADVNoPanic(t *testing.T) {
	for _, body := range [][]byte{
		nil,
		{},
		{0x00},
		bytes.Repeat([]byte{0xFF}, 1024),
	} {
		_, err := ParseResourceAdv(body)
		if err == nil {
			t.Errorf("expected error for malformed body %x", body)
			continue
		}
		if !errors.Is(err, ErrResourceADVMalformed) {
			t.Errorf("err = %v, want wrapped ErrResourceADVMalformed", err)
		}
	}
}
